command:
// =========================
// FACTION RELATIONSHIP GENERATOR
// Creates Journal Entry
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

const options = await Dialog.prompt({
    title: "Faction Relationship Generator",
    content: `
    <p>Faction Roll Table Name:</p>
    <input id="tableName" type="text" value="Sandbox Factions"/>

    <p>Journal Name:</p>
    <input id="journalName" type="text" value="Faction Relationships"/>
    `,
    callback: html => ({
        tableName: html.find("#tableName").val(),
                       journalName: html.find("#journalName").val()
    })
});

const table = game.tables.getName(options.tableName);

if (!table) {
    ui.notifications.error(`Could not find roll table: ${options.tableName}`);
    return;
}

const factions = table.results.contents.map(r => {
    const text = r.text;
    const name = text.split("|")[0].trim();
    return {
        name,
        full: text
    };
});

if (factions.length < 2) {
    ui.notifications.error("Need at least 2 factions.");
    return;
}

const relationshipTable = {
    2: "War",
    3: "Hostile",
    4: "Rivalry",
    5: "Suspicious",
    6: "Neutral",
    7: "Neutral",
    8: "Trade",
    9: "Friendly",
    10: "Allied",
    11: "Close Allies",
    12: "Vassal / Protectorate"
};

let output = `
<h1>Faction Relationships</h1>

<p>
Generated from:
<b>${options.tableName}</b>
</p>

<hr>
`;

let matrix = {};

for (let i = 0; i < factions.length; i++) {

    const factionA = factions[i];

    matrix[factionA.name] = {};

    for (let j = i + 1; j < factions.length; j++) {

        const factionB = factions[j];

        const d1 = roll(6);
        const d2 = roll(6);

        const total = d1 + d2;

        const relationship = relationshipTable[total];

        matrix[factionA.name][factionB.name] = relationship;

        output += `
        <h3>${factionA.name} ↔ ${factionB.name}</h3>

        <p>
        <b>Roll:</b> 2d6 = ${d1} + ${d2} = ${total}
        </p>

        <p>
        <b>Relationship:</b> ${relationship}
        </p>

        <hr>
        `;
    }
}

const existing = game.journal.getName(options.journalName);

if (existing) {
    await existing.delete();
}

await JournalEntry.create({
    name: options.journalName,
    pages: [{
        name: "Relationships",
        type: "text",
        text: {
            content: output
        }
    }]
});

ChatMessage.create({
    speaker: ChatMessage.getSpeaker(),
                   content: `
                   <h2>Faction Relationships Generated</h2>

                   <p><b>Factions:</b> ${factions.length}</p>

                   <p><b>Journal Created:</b> ${options.journalName}</p>

                   <p>
                   Open the journal to view all faction relationships.
                   </p>
                   `
});
